import { Component, Element, Event, EventEmitter, h, Prop, State } from '@stencil/core';
import type { MediaAspect, LandscapeRatio, PortraitRatio } from '../wdpr-media/wdpr-media';

export type MediaHeroVariant = 'video' | 'photo-360' | 'photograph';

@Component({
  tag: 'wdpr-media-hero',
  shadow: true,
  styles: ':host { display: block; width: 100%; }',
})
export class WdprMediaHero {
  @Prop() variant: MediaHeroVariant = 'video';
  @Prop() src!: string;
  @Prop() videoSrc?: string;
  @Prop() poster?: string;
  @Prop() alt = '';
  @Prop() titleText = '';
  @Prop() label?: string;
  @Prop() captionsSrc?: string;
  @Prop() showMediaButton = false;
  @Prop() mediaButtonLabel = 'View';
  @Prop() aspect: MediaAspect = 'portrait';
  @Prop() ratio: string = '3:4';

  @Event({ eventName: 'view360Click' }) view360Click: EventEmitter<void>;
  @Event({ eventName: 'mediaButtonClick' }) mediaButtonClick: EventEmitter<void>;

  @State() fullscreen: false | 'video' | '360' | 'photo' = false;

  @Element() el!: HTMLElement;

  componentDidUpdate() {
    if (this.fullscreen) {
      (this.el.shadowRoot?.querySelector('[data-fullscreen]') as HTMLElement)?.focus();
    }
  }

  private renderFullscreenShell(label: string, children: unknown) {
    return (
      <div
        class="fixed inset-0 z-50 flex flex-col bg-black"
        role="dialog"
        aria-modal="true"
        aria-label={label}
        tabindex={-1}
        data-fullscreen
        onKeyDown={(e: KeyboardEvent) => e.key === 'Escape' && (this.fullscreen = false)}
      >
        <wdpr-page-header title-text={this.titleText} background="transparent" inverse={true}>
          <wdpr-icon-button
            slot="leading-icon"
            iconName="previous"
            a11yLabel="Go back"
            variant="inverse"
            onClicked={() => (this.fullscreen = false)}
          />
        </wdpr-page-header>
        {children}
      </div>
    );
  }

  private renderVideoFullscreen() {
    return this.renderFullscreenShell(
      this.titleText || 'Video',
      <div class="flex-1 overflow-hidden">
        <wdpr-media-player
          src={this.videoSrc || this.src}
          poster={this.poster}
          captions-src={this.captionsSrc}
          captions-position="top"
          show-controls={true}
          show-time={true}
          show-mute-toggle={true}
          show-fullscreen-button={false}
          show-play-toggle-on-control={true}
          show-progress-bar={true}
          show-captions-toggle={!!this.captionsSrc}
          show-audio-chip={false}
          class="w-full h-full"
        />
      </div>
    );
  }

  private render360Fullscreen() {
    return this.renderFullscreenShell(
      this.titleText || '360° Photo',
      <div class="flex-1 flex items-center justify-center overflow-hidden">
        <img src={this.src} alt={this.alt} class="max-w-full max-h-full object-contain" />
      </div>
    );
  }

  private renderMedia(objectFit: 'cover' | 'contain' = 'cover') {
    return (
      <wdpr-media
        src={this.src}
        alt={this.alt}
        aspect={this.aspect}
        landscape-ratio={this.aspect === 'landscape' ? this.ratio as LandscapeRatio : undefined}
        portrait-ratio={this.aspect === 'portrait' ? this.ratio as PortraitRatio : undefined}
        object-fit={objectFit}
        class="w-full"
      />
    );
  }

  private renderLabel() {
    if (!this.label) return null;

    return (
      <div class="absolute bottom-200 right-200 z-30">
        <span class={labelClasses}>{this.label}</span>
      </div>
    );
  }

  private renderNavButtons() {
    return (
      <div class="absolute inset-x-0 top-0 z-30 flex items-center justify-between p-200">
        <slot name="leading-icon" />
        <slot name="trailing-icon" />
      </div>
    );
  }

  private renderMediaButton() {
    if (!this.showMediaButton) return null;

    return (
      <div class="absolute bottom-200 left-200 z-30">
        <button
          type="button"
          class={mediaButtonClasses}
          aria-label={`${this.mediaButtonLabel} media gallery`}
          onClick={() => this.mediaButtonClick.emit()}
        >
          {this.mediaButtonLabel}
        </button>
      </div>
    );
  }

  private renderScrim() {
    return <div class={scrimClasses} />;
  }

  private renderVideo() {
    return (
      <div class="relative w-full">
        <wdpr-media-player
          src={this.videoSrc || this.src}
          poster={this.poster}
          captions-src={this.captionsSrc}
          show-controls={false}
          show-audio-chip={false}
          class="w-full"
        />
        {this.renderScrim()}
        {this.renderNavButtons()}
        <div class="absolute inset-0 z-20 flex items-center justify-center">
          <wdpr-media-player-control-play-toggle
            playing={false}
            variant="overlay"
            onWdprPlayToggle={() => (this.fullscreen = 'video')}
          />
        </div>
        {this.renderLabel()}
        {this.renderMediaButton()}
      </div>
    );
  }

  private renderPhoto360() {
    return (
      <div class="relative w-full">
        {this.renderMedia()}
        {this.renderScrim()}
        {this.renderNavButtons()}
        <div class="absolute inset-0 z-20 flex items-center justify-center">
          <wdpr-media-hero-360-chip onView360Toggle={() => { this.fullscreen = '360'; this.view360Click.emit(); }} />
        </div>
        {this.renderLabel()}
        {this.renderMediaButton()}
      </div>
    );
  }

  private renderPhotograph() {
    return (
      <div class="relative w-full">
        {this.renderMedia()}
        {this.renderScrim()}
        {this.renderNavButtons()}
        <button
          type="button"
          class="absolute inset-0 z-15 cursor-pointer bg-transparent border-none p-0"
          aria-label="View photo fullscreen"
          onClick={() => (this.fullscreen = 'photo')}
        />
        {this.renderLabel()}
        {this.renderMediaButton()}
      </div>
    );
  }

  private renderPhotographFullscreen() {
    return this.renderFullscreenShell(
      this.titleText || 'Photo fullscreen',
      <div class="flex-1 flex items-center justify-center overflow-hidden">
        <img src={this.src} alt={this.alt} class="max-w-full max-h-full object-contain" />
      </div>
    );
  }

  render() {
    if (this.fullscreen === 'video') return this.renderVideoFullscreen();
    if (this.fullscreen === '360') return this.render360Fullscreen();
    if (this.fullscreen === 'photo') return this.renderPhotographFullscreen();

    switch (this.variant) {
      case 'video':
        return this.renderVideo();
      case 'photo-360':
        return this.renderPhoto360();
      case 'photograph':
        return this.renderPhotograph();
      default:
        return this.renderVideo();
    }
  }
}

const scrimClasses =
  'absolute inset-x-0 top-0 h-[30%] z-20 bg-gradient-to-b from-[rgba(0,0,0,0.45)] to-transparent pointer-events-none';

const labelClasses = `
  inline-flex items-center rounded-full px-200 py-075
  bg-surface-actionable-alt-default-a68
  text-icon-actionable-inverse-default text-body-small font-semibold
  select-none
`;

const mediaButtonClasses = `
  cursor-pointer inline-flex items-center rounded-pill px-300 py-100
  bg-surface-actionable-alt-default-a78 hover:bg-surface-actionable-alt-hover-a88 active:bg-surface-actionable-alt-pressed disabled:bg-surface-actionable-alt-disabled
  elevation-xsmall-soft
  text-icon-actionable-inverse-default text-body-small font-semibold
  border border-white
  focus:outline-none focus-visible:outline-037 focus-visible:outline-stroke-actionable-alt-focused focus-visible:outline-solid focus-visible:outline-offset-2
  transition-colors duration-150
`;
